import React, { useState } from 'react';
import { Outlet, useNavigate, NavLink } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { 
  FaTachometerAlt, 
  FaMoneyBillWave, 
  FaPiggyBank, 
  FaChartLine, 
  FaRobot, 
  FaSignOutAlt,
  FaBars,
  FaTimes,
  FaUserCircle
} from 'react-icons/fa';

const Layout = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const menuItems = [
    { path: '/dashboard', icon: FaTachometerAlt, label: 'Dashboard' },
    { path: '/transactions', icon: FaMoneyBillWave, label: 'Transactions' },
    { path: '/budgets', icon: FaPiggyBank, label: 'Budgets' },
    { path: '/reports', icon: FaChartLine, label: 'Reports' },
    { path: '/ai', icon: FaRobot, label: 'AI Insights' },
  ];

  return (
    <div className="flex h-screen bg-slate-950 bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-slate-900 via-zinc-950 to-black text-slate-100 font-sans antialiased overflow-hidden">
      {/* Mobile sidebar toggle */}
      <button
        className="lg:hidden fixed top-4 left-4 z-30 p-3 bg-slate-800/80 backdrop-blur-md border border-white/10 rounded-xl text-white shadow-lg shadow-black/40 hover:bg-slate-700 transition-all duration-200"
        onClick={() => setSidebarOpen(!sidebarOpen)}
      >
        {sidebarOpen ? <FaTimes className="text-lg" /> : <FaBars className="text-lg" />}
      </button>

      {/* Sidebar */}
      <aside className={`fixed lg:relative z-20 w-64 bg-slate-900/60 backdrop-blur-xl border-r border-white/5 h-full transition-all duration-300 ease-out flex flex-col justify-between ${
        sidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'
      }`}>
        <div>
          {/* Logo Brand */}
          <div className="p-6 border-b border-white/5">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-gradient-to-tr from-violet-600 to-indigo-600 rounded-xl shadow-lg shadow-indigo-500/30 text-white animate-pulse">
                <FaPiggyBank className="text-xl" />
              </div>
              <div>
                <h2 className="text-lg font-extrabold bg-gradient-to-r from-white via-slate-200 to-slate-400 bg-clip-text text-transparent tracking-tight">SmartExpense</h2>
                <span className="text-[10px] uppercase font-bold tracking-widest text-violet-400 bg-violet-500/10 px-2 py-0.5 rounded-full">v1.2.0</span>
              </div>
            </div>
          </div>

          {/* User profile brief */}
          <div className="mx-4 my-4 p-3 bg-white/5 border border-white/5 rounded-2xl flex items-center gap-3">
            <div className="relative">
              <FaUserCircle className="text-4xl text-slate-400" />
              <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-emerald-500 rounded-full border-2 border-slate-900 animate-ping"></div>
              <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-emerald-500 rounded-full border-2 border-slate-900"></div>
            </div>
            <div className="overflow-hidden">
              <p className="text-xs text-slate-400 font-medium">Logged in as</p>
              <h4 className="text-sm font-semibold text-slate-200 truncate">{user?.name || "Guest"}</h4>
            </div>
          </div>

          {/* Navigation Items */}
          <nav className="px-3 space-y-1">
            {menuItems.map((item) => (
              <NavLink
                key={item.path}
                to={item.path}
                className={({ isActive }) =>
                  `flex items-center gap-3.5 px-4 py-3 rounded-xl font-medium transition-all duration-300 group ${
                    isActive 
                      ? 'bg-gradient-to-r from-violet-600/35 to-indigo-600/35 text-white border border-violet-500/20 shadow-md shadow-violet-500/5' 
                      : 'text-slate-400 hover:text-slate-200 hover:bg-white/[0.04]'
                  }`
                }
                onClick={() => setSidebarOpen(false)}
              >
                {({ isActive }) => (
                  <>
                    <item.icon className={`text-lg transition-transform duration-300 group-hover:scale-110 ${isActive ? 'text-violet-400' : 'text-slate-500 group-hover:text-slate-300'}`} />
                    <span>{item.label}</span>
                    {isActive && <div className="ml-auto w-1.5 h-1.5 bg-violet-400 rounded-full shadow-lg shadow-violet-400/80"></div>}
                  </>
                )}
              </NavLink>
            ))}
          </nav>
        </div>

        {/* Logout Section */}
        <div className="p-4 border-t border-white/5">
          <button
            onClick={handleLogout}
            className="w-full flex items-center gap-3.5 px-4 py-3 rounded-xl font-medium text-rose-400 hover:text-rose-300 hover:bg-rose-500/10 border border-transparent hover:border-rose-500/20 transition-all duration-300 group"
          >
            <FaSignOutAlt className="text-lg transition-transform duration-300 group-hover:-translate-x-1" />
            <span>Logout</span>
          </button>
        </div>
      </aside>

      {/* Main content wrapper */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Subtle background glows */}
        <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] rounded-full bg-violet-600/10 blur-[120px] pointer-events-none"></div>
        <div className="absolute bottom-[-15%] left-[-5%] w-[400px] h-[400px] rounded-full bg-blue-600/5 blur-[100px] pointer-events-none"></div>

        <div className="flex-1 overflow-y-auto overflow-x-hidden p-6 lg:p-10 z-10">
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default Layout;
